   489→    private func handleScreenCaptureError(_ error: Error) {
   490→        let nsError = error as NSError
   491→        logCaptureError(error, context: "Screen capture error")
   492→        if nsError.domain == SCStreamErrorDomain, nsError.code == -3801 {
   493→            needsScreenRecordingPermission = true
   494→            let bundlePath = Bundle.main.bundleURL.path
   495→            errorMessage = "Screen Recording permission was denied for this app instance. Enable it in System Settings → Privacy & Security → Screen Recording, then quit and relaunch. App path: \(bundlePath)"
   496→            return
   497→        }
   498→        needsScreenRecordingPermission = false
   499→        errorMessage = formatError(error)
   500→    }
