   548→final class ScreenRecorder: NSObject, SCStreamOutput, SCStreamDelegate {
   549→    var onPreviewSample: ((CMSampleBuffer) -> Void)?
   550→    var onError: ((Error) -> Void)?
   551→
   552→    private let streamQueue = DispatchQueue(label: "ScreenRecorder.stream")
   553→    private let stateQueue = DispatchQueue(label: "ScreenRecorder.state")
   554→    private var stream: SCStream?
   555→    private var writer: ScreenAssetWriter?
   556→    private var currentOutputURL: URL?
   557→
   558→    func startCapture(display: SCDisplay) async throws {
   559→        let filter = SCContentFilter(display: display, excludingWindows: [])
   560→        let config = SCStreamConfiguration()
   561→        let width = CGDisplayPixelsWide(display.displayID)
   562→        let height = CGDisplayPixelsHigh(display.displayID)
   563→        let evenWidth = width - (width % 2)
   564→        let evenHeight = height - (height % 2)
   565→        config.width = max(2, evenWidth)
   566→        config.height = max(2, evenHeight)
   567→        config.sourceRect = CGRect(x: 0, y: 0, width: CGFloat(display.width), height: CGFloat(display.height))
   568→        config.captureResolution = .best
   569→        config.minimumFrameInterval = CMTime(value: 1, timescale: 30)
   570→        config.queueDepth = 6
   571→        config.pixelFormat = kCVPixelFormatType_420YpCbCr8BiPlanarFullRange
   572→        config.showsCursor = true
   573→        config.capturesAudio = false
   574→
   575→        let stream = SCStream(filter: filter, configuration: config, delegate: self)
   576→        do {
   577→            try stream.addStreamOutput(self, type: .screen, sampleHandlerQueue: streamQueue)
   578→        } catch {
   579→            throw error
   580→        }
   581→
   582→        try await stream.startCapture()
   583→
   584→        stateQueue.sync {
   585→            self.stream = stream
   586→        }
   587→    }
   588→
   589→    func stopCapture() async {
   590→        let stream = stateQueue.sync { self.stream }
   591→        guard let stream else { return }
   592→        try? await stream.stopCapture()
   593→        stateQueue.sync {
   594→            self.stream = nil
   595→        }
   596→    }
   597→
   598→    func startRecording(outputURL: URL, includeAudio: Bool, pauseController: PauseController) {
   599→        let writer = ScreenAssetWriter(outputURL: outputURL, includeAudio: includeAudio, pauseController: pauseController)
   600→        stateQueue.sync {
   601→            self.writer = writer
   602→            self.currentOutputURL = outputURL
   603→        }
   604→    }
   605→
   606→    func prepareRecording(outputURL: URL) {
   607→        stateQueue.sync {
   608→            self.currentOutputURL = outputURL
   609→        }
   610→    }
   611→
   612→    func stopRecording(completion: @escaping (Result<URL, Error>) -> Void) {
   613→        let (writer, outputURL) = stateQueue.sync { () -> (ScreenAssetWriter?, URL?) in
   614→            defer { self.writer = nil }
   615→            let url = self.currentOutputURL
   616→            self.currentOutputURL = nil
   617→            return (self.writer, url)
   618→        }
   619→        guard let writer else {
   620→            completion(.success(outputURL ?? URL(fileURLWithPath: "")))
   621→            return
   622→        }
   623→        writer.finish(completion: completion)
   624→    }
   625→
   626→    func appendAudio(_ sampleBuffer: CMSampleBuffer) {
   627→        let writer = stateQueue.sync { self.writer }
   628→        writer?.appendAudio(sampleBuffer: sampleBuffer)
   629→    }
   630→
   631→    func resetPendingVideoSample() {
   632→        let writer = stateQueue.sync { self.writer }
   633→        writer?.resetPendingVideoSample()
   634→    }
   635→
   636→    func stream(_ stream: SCStream, didOutputSampleBuffer sampleBuffer: CMSampleBuffer, of type: SCStreamOutputType) {
   637→        guard type == .screen else { return }
   638→        guard CMSampleBufferDataIsReady(sampleBuffer) else { return }
   639→
   640→        onPreviewSample?(sampleBuffer)
   641→
   642→        let writer = stateQueue.sync { self.writer }
   643→        writer?.appendVideo(sampleBuffer: sampleBuffer)
   644→    }
   645→
   646→    func stream(_ stream: SCStream, didStopWithError error: Error) {
   647→        onError?(error)
   648→    }
   649→}
