   651→final class MicAudioCapture: NSObject, AVCaptureAudioDataOutputSampleBufferDelegate {
   652→    var onAudioSample: ((CMSampleBuffer) -> Void)?
   653→    var onError: ((Error) -> Void)?
   654→
   655→    private let session = AVCaptureSession()
   656→    private let sessionQueue = DispatchQueue(label: "MicAudioCapture.session")
   657→    private let outputQueue = DispatchQueue(label: "MicAudioCapture.output")
   658→    private var isConfigured = false
   659→
   660→    func start() {
   661→        sessionQueue.async {
   662→            if !self.isConfigured {
   663→                self.configureSession()
   664→            }
   665→            guard !self.session.isRunning else { return }
   666→            self.session.startRunning()
   667→        }
   668→    }
   669→
   670→    func stop() {
   671→        sessionQueue.async {
   672→            if self.session.isRunning {
