   840→                    self.waitingForAudio = true
   841→                    let work = DispatchWorkItem { [weak self] in
   842→                        self?.queue.async {
   843→                            self?.configureIfPossible(forceVideoOnly: true)
   844→                            self?.waitingForAudio = false
   845→                            self?.audioWaitWorkItem = nil
   846→                        }
   847→                    }
