   860→    func appendAudio(sampleBuffer: CMSampleBuffer) {
   861→        queue.async {
   862→            guard !self.isFinishing else { return }
   863→            guard CMSampleBufferDataIsReady(sampleBuffer) else { return }
   864→            guard !self.pauseController.shouldDropSamples() else { return }
