   895→    func finish(completion: @escaping (Result<URL, Error>) -> Void) {
   896→        queue.async {
   897→            guard let writer = self.writer else {
   898→                completion(.success(self.outputURL))
   899→                return
   900→            }
   901→            if self.isFinishing {
   902→                completion(.success(self.outputURL))
   903→                return
   904→            }
