   941→    private func configureWriter(videoSample: CMSampleBuffer, enableAudio: Bool) throws {
   942→        if FileManager.default.fileExists(atPath: outputURL.path) {
   943→            try? FileManager.default.removeItem(at: outputURL)
   944→        }
   945→
   946→        let writer = try AVAssetWriter(outputURL: outputURL, fileType: .mov)
   947→
   948→        guard let formatDescription = CMSampleBufferGetFormatDescription(videoSample) else {
   949→            throw NSError(domain: "ScreenAssetWriter", code: -1)
   950→        }
   951→        let dimensions = CMVideoFormatDescriptionGetDimensions(formatDescription)
   952→        let resolvedCodec = Self.resolvedCodec(preferred: codec, dimensions: dimensions)
   953→
   954→        var compression: [String: Any] = [
   955→            AVVideoAverageBitRateKey: 12_000_000,
   956→            AVVideoExpectedSourceFrameRateKey: 30,
   957→            AVVideoMaxKeyFrameIntervalKey: 60
   958→        ]
   959→        if resolvedCodec == .h264 {
   960→            compression[AVVideoProfileLevelKey] = AVVideoProfileLevelH264HighAutoLevel
   961→        }
   962→
   963→        let videoSettings: [String: Any] = [
   964→            AVVideoCodecKey: resolvedCodec,
   965→            AVVideoWidthKey: Int(dimensions.width),
   966→            AVVideoHeightKey: Int(dimensions.height),
   967→            AVVideoCompressionPropertiesKey: compression
   968→        ]
   969→
   970→        let videoInput = AVAssetWriterInput(
   971→            mediaType: .video,
   972→            outputSettings: videoSettings,
   973→            sourceFormatHint: formatDescription
   974→        )
   975→        videoInput.expectsMediaDataInRealTime = true
   976→        guard writer.canAdd(videoInput) else {
   977→            throw NSError(domain: "ScreenAssetWriter", code: -2)
   978→        }
   979→        writer.add(videoInput)
   980→
   981→        var audioInput: AVAssetWriterInput?
   982→        if enableAudio, let audioFormat {
   983→            let audioSettings: [String: Any] = [
   984→                AVFormatIDKey: kAudioFormatMPEG4AAC,
   985→                AVSampleRateKey: audioFormat.sampleRate,
   986→                AVNumberOfChannelsKey: audioFormat.channels,
   987→                AVEncoderBitRateKey: 128_000
   988→            ]
   989→            let input = AVAssetWriterInput(mediaType: .audio, outputSettings: audioSettings)
   990→            input.expectsMediaDataInRealTime = true
   991→            if writer.canAdd(input) {
   992→                writer.add(input)
   993→                audioInput = input
   994→            }
   995→        }
   996→
   997→        self.writer = writer
   998→        self.videoInput = videoInput
   999→        self.audioInput = audioInput
  1000→    }
