  1002→    private func appendVideoInternal(_ sampleBuffer: CMSampleBuffer) {
  1003→        guard let writer, let input = videoInput else { return }
  1004→
  1005→        let offset = pauseController.currentOffset()
  1006→        if !didStartSession {
  1007→            if !writer.startWriting() {
  1008→                logAssetWriterFailure(writer, context: "ScreenAssetWriter startWriting failed")
  1009→                return
  1010→            }
  1011→            let rawStart = CMTimeSubtract(CMSampleBufferGetPresentationTimeStamp(sampleBuffer), offset)
  1012→            let startTime = CMTimeCompare(rawStart, .zero) < 0 ? .zero : rawStart
  1013→            writer.startSession(atSourceTime: startTime)
  1014→            didStartSession = true
  1015→            sessionStartTime = startTime
  1016→        }
  1017→
  1018→        guard input.isReadyForMoreMediaData else { return }
  1019→        let adjusted = SampleBufferTiming.adjust(sampleBuffer, by: offset) ?? sampleBuffer
  1020→        let pts = CMSampleBufferGetPresentationTimeStamp(adjusted)
  1021→        if pts.isValid, CMTimeCompare(pts, .zero) < 0 {
  1022→            return
  1023→        }
  1024→        if pts.isValid, let last = lastVideoPTS, CMTimeCompare(pts, last) <= 0 {
  1025→            return
  1026→        }
  1027→        lastVideoPTS = pts.isValid ? pts : lastVideoPTS
  1028→        if !input.append(adjusted) {
  1029→            if !didLogVideoAppendFailure {
  1030→                didLogVideoAppendFailure = true
  1031→                logAssetWriterFailure(writer, context: "ScreenAssetWriter video append failed")
  1032→            }
  1033→        }
  1034→    }
  1035→
  1036→    private func appendAudioInternal(_ sampleBuffer: CMSampleBuffer) {
  1037→        guard didStartSession, let writer, let input = audioInput else { return }
  1038→        guard input.isReadyForMoreMediaData else { return }
  1039→        let offset = pauseController.currentOffset()
  1040→        let adjusted = SampleBufferTiming.adjust(sampleBuffer, by: offset) ?? sampleBuffer
  1041→        let pts = CMSampleBufferGetPresentationTimeStamp(adjusted)
  1042→        if let sessionStartTime, pts.isValid, CMTimeCompare(pts, sessionStartTime) < 0 {
  1043→            return
  1044→        }
  1045→        if pts.isValid, CMTimeCompare(pts, .zero) < 0 {
  1046→            return
  1047→        }
  1048→        if pts.isValid, let last = lastAudioPTS, CMTimeCompare(pts, last) <= 0 {
  1049→            return
  1050→        }
  1051→        lastAudioPTS = pts.isValid ? pts : lastAudioPTS
  1052→        if !input.append(adjusted) {
  1053→            if !didLogAudioAppendFailure {
  1054→                didLogAudioAppendFailure = true
  1055→                logAssetWriterFailure(writer, context: "ScreenAssetWriter audio append failed")
  1056→            }
  1057→        }
  1058→    }
  1059→
  1060→    private static func extractAudioFormat(sampleBuffer: CMSampleBuffer) -> AudioFormat? {
  1061→        guard let formatDescription = CMSampleBufferGetFormatDescription(sampleBuffer) else { return nil }
  1062→        guard let asbd = CMAudioFormatDescriptionGetStreamBasicDescription(formatDescription) else { return nil }
  1063→        return AudioFormat(sampleRate: asbd.pointee.mSampleRate, channels: Int(asbd.pointee.mChannelsPerFrame))
  1064→    }
  1065→
  1066→    private static func resolvedCodec(preferred: AVVideoCodecType, dimensions: CMVideoDimensions) -> AVVideoCodecType {
  1067→        guard preferred == .h264 else { return preferred }
  1068→        let maxDimension = max(Int(dimensions.width), Int(dimensions.height))
  1069→        if maxDimension > h264MaxDimension {
  1070→            return .hevc
  1071→        }
  1072→        return preferred
  1073→    }
  1074→}
  1075→
  1076→enum SampleBufferTiming {
  1077→    static func adjust(_ sampleBuffer: CMSampleBuffer, by offset: CMTime) -> CMSampleBuffer? {
  1078→        if CMTimeCompare(offset, .zero) == 0 {
  1079→            return sampleBuffer
  1080→        }
  1081→
  1082→        var timingCount: CMItemCount = 0
  1083→        let status = CMSampleBufferGetSampleTimingInfoArray(
  1084→            sampleBuffer,
  1085→            entryCount: 0,
  1086→            arrayToFill: nil,
  1087→            entriesNeededOut: &timingCount
  1088→        )
  1089→        guard status == noErr, timingCount > 0 else {
  1090→            return sampleBuffer
  1091→        }
  1092→
  1093→        let count = Int(timingCount)
  1094→        var timingInfo = Array(repeating: CMSampleTimingInfo(), count: count)
  1095→        let status2 = CMSampleBufferGetSampleTimingInfoArray(
  1096→            sampleBuffer,
  1097→            entryCount: count,
  1098→            arrayToFill: &timingInfo,
  1099→            entriesNeededOut: &timingCount
  1100→        )
  1101→        guard status2 == noErr else {
  1102→            return sampleBuffer
  1103→        }
  1104→
  1105→        for index in 0..<timingInfo.count {
  1106→            if timingInfo[index].decodeTimeStamp.isValid {
  1107→                timingInfo[index].decodeTimeStamp = CMTimeSubtract(timingInfo[index].decodeTimeStamp, offset)
  1108→            }
  1109→            if timingInfo[index].presentationTimeStamp.isValid {
  1110→                timingInfo[index].presentationTimeStamp = CMTimeSubtract(timingInfo[index].presentationTimeStamp, offset)
  1111→            }
  1112→        }
  1113→
  1114→        var adjusted: CMSampleBuffer?
  1115→        let status3 = CMSampleBufferCreateCopyWithNewTiming(
  1116→            allocator: kCFAllocatorDefault,
  1117→            sampleBuffer: sampleBuffer,
  1118→            sampleTimingEntryCount: timingInfo.count,
  1119→            sampleTimingArray: &timingInfo,
  1120→            sampleBufferOut: &adjusted
  1121→        )
  1122→        guard status3 == noErr else {
  1123→            return sampleBuffer
  1124→        }
  1125→        return adjusted
  1126→    }
  1127→}
