  1129→private func logCaptureError(_ error: Error, context: String) {
  1130→    let nsError = error as NSError
  1131→    let underlying = nsError.userInfo[NSUnderlyingErrorKey] as? NSError
  1132→    let underlyingText = underlying.map { "\($0.localizedDescription) (\($0.domain) \($0.code))" } ?? "none"
  1133→    captureLogger.error(
  1134→        "\(context, privacy: .public): \(nsError.localizedDescription, privacy: .public) (\(nsError.domain, privacy: .public) \(nsError.code)) underlying=\(underlyingText, privacy: .public)"
  1135→    )
  1136→}
  1137→
  1138→private func logAssetWriterFailure(_ writer: AVAssetWriter, context: String) {
  1139→    let errorText = writer.error.map { "\($0.localizedDescription) (\(($0 as NSError).domain) \(($0 as NSError).code))" } ?? "none"
  1140→    captureLogger.error(
  1141→        "\(context, privacy: .public): status=\(writer.status.rawValue) error=\(errorText, privacy: .public)"
  1142→    )
  1143→}
