   191→    private func timerOverlayContent(elapsed: TimeInterval, size: CGSize, radius: CGFloat) -> some View {
   192→        let progress = (elapsed / 60).truncatingRemainder(dividingBy: 1)
   193→        let trailLength = 0.06
   194→        let color = timerColor(for: elapsed)
   195→        let center = CGPoint(x: size.width / 2, y: size.height / 2)
   196→        let angle = Angle.degrees(progress * 360 - 90)
   197→        let dotPoint = CGPoint(
   198→            x: center.x + cos(angle.radians) * radius * 1.07,
   199→            y: center.y + sin(angle.radians) * radius * 1.07
   200→        )
   201→        let segments = trailSegments(progress: progress, length: trailLength)
   202→
   203→        return ZStack {
   204→            ZStack {
   205→                ForEach(segments.indices, id: \.self) { index in
   206→                    let segment = segments[index]
   207→                    Circle()
   208→                        .trim(from: segment.start, to: segment.end)
   209→                        .stroke(
   210→                            AngularGradient(
   211→                                gradient: Gradient(stops: [
   212→                                    .init(color: color.opacity(0.0), location: 0),
   213→                                    .init(color: color.opacity(0.35), location: 1)
   214→                                ]),
   215→                                center: .center,
   216→                                startAngle: .degrees(segment.start * 360),
   217→                                endAngle: .degrees(segment.end * 360)
   218→                            ),
   219→                            style: StrokeStyle(lineWidth: 4, lineCap: .round)
   220→                        )
   221→                }
   222→            }
   223→            .rotationEffect(.degrees(-90))
   224→
   225→            Circle()
   226→                .fill(color)
   227→                .frame(width: 6, height: 6)
   228→                .shadow(color: color.opacity(0.5), radius: 3)
   229→                .position(dotPoint)
   230→        }
   231→    }
   232→
   233→    private func trailSegments(progress: Double, length: Double) -> [(start: Double, end: Double)] {
   234→        let start = progress - length
   235→        if start >= 0 {
   236→            return [(start, progress)]
   237→        }
   238→        return [(start + 1, 1), (0, progress)]
   239→    }
