   241→    private func timerColor(for elapsed: TimeInterval) -> Color {
   242→        let colors: [NSColor] = [
   243→            .systemRed,
   244→            .systemOrange,
   245→            .systemYellow,
   246→            .systemGreen,
   247→            .systemTeal,
   248→            .systemBlue,
   249→            .systemPurple
   250→        ]
   251→        let minutes = max(0, elapsed / 60)
   252→        let base = floor(minutes)
   253→        let t = CGFloat(minutes - base)
   254→        let index = Int(base) % colors.count
   255→        let nextIndex = (index + 1) % colors.count
   256→        return interpolateColor(colors[index], colors[nextIndex], t: t)
   257→    }
   258→
   259→    private func interpolateColor(_ a: NSColor, _ b: NSColor, t: CGFloat) -> Color {
   260→        let aColor = a.usingColorSpace(.deviceRGB) ?? a
   261→        let bColor = b.usingColorSpace(.deviceRGB) ?? b
   262→        var ar: CGFloat = 0
   263→        var ag: CGFloat = 0
   264→        var ab: CGFloat = 0
   265→        var aa: CGFloat = 0
   266→        var br: CGFloat = 0
   267→        var bg: CGFloat = 0
   268→        var bb: CGFloat = 0
   269→        var ba: CGFloat = 0
   270→        aColor.getRed(&ar, green: &ag, blue: &ab, alpha: &aa)
   271→        bColor.getRed(&br, green: &bg, blue: &bb, alpha: &ba)
   272→        let r = ar + (br - ar) * t
   273→        let g = ag + (bg - ag) * t
   274→        let b = ab + (bb - ab) * t
   275→        let a = aa + (ba - aa) * t
   276→        return Color(.sRGB, red: Double(r), green: Double(g), blue: Double(b), opacity: Double(a))
   277→    }
