   298→    private func resizeWindow(by delta: CGFloat) {
   299→        guard let window = resolveWindowForResize() else { return }
   300→        let currentSize = window.frame.size
   301→        let currentLength = min(currentSize.width, currentSize.height)
   302→        let minSize: CGFloat = 180
   303→        let maxSize: CGFloat = maxAllowedWindowSize(for: window)
   304→        let newLength = min(max(currentLength + delta, minSize), maxSize)
   305→
   306→        let center = CGPoint(x: window.frame.midX, y: window.frame.midY)
   307→        let newFrame = CGRect(
   308→            x: center.x - newLength / 2,
   309→            y: center.y - newLength / 2,
   310→            width: newLength,
   311→            height: newLength
   312→        )
   313→        window.setFrame(newFrame, display: true, animate: true)
   314→    }
