   413→private struct WindowAccessor: NSViewRepresentable {
   414→    let aspectRatio: CGFloat
   415→    let configure: (NSWindow, CGFloat) -> Void
   416→    let onWindow: (NSWindow) -> Void
   417→
   418→    func makeCoordinator() -> Coordinator {
   419→        Coordinator()
   420→    }
   421→
   422→    func makeNSView(context: Context) -> NSView {
   423→        let view = NSView(frame: .zero)
   424→        DispatchQueue.main.async {
   425→            self.updateWindow(for: view, context: context)
   426→        }
   427→        return view
   428→    }
