   430→    func updateNSView(_ nsView: NSView, context: Context) {
   431→        updateWindow(for: nsView, context: context)
   432→    }
   433→
   434→    private func updateWindow(for view: NSView, context: Context) {
   435→        guard let window = view.window else { return }
   436→
   437→        if context.coordinator.window !== window {
   438→            context.coordinator.window = window
   439→            context.coordinator.didWrapContent = false
   440→            onWindow(window)
   441→        }
   442→
   443→        if !context.coordinator.didWrapContent {
   444→            wrapContentView(in: window)
   445→            context.coordinator.didWrapContent = true
   446→        }
   447→
   448→        if context.coordinator.lastAspectRatio != aspectRatio {
   449→            configure(window, aspectRatio)
   450→            context.coordinator.lastAspectRatio = aspectRatio
   451→        }
   452→    }
   453→
   454→    private func wrapContentView(in window: NSWindow) {
   455→        guard let contentView = window.contentView else { return }
   456→        guard !(contentView is CircleHitTestView) else { return }
   457→
   458→        let container = CircleHitTestView(frame: contentView.frame)
   459→        container.autoresizingMask = [.width, .height]
   460→        contentView.frame = container.bounds
   461→        contentView.autoresizingMask = [.width, .height]
   462→        container.addSubview(contentView)
   463→        window.contentView = container
   464→    }
   465→
   466→    final class Coordinator {
   467→        var window: NSWindow?
   468→        var lastAspectRatio: CGFloat?
   469→        var didWrapContent = false
   470→    }
   471→}
