   473→final class CircleHitTestView: NSView {
   474→    override func hitTest(_ point: NSPoint) -> NSView? {
   475→        let radius = min(bounds.width, bounds.height) / 2
   476→        let center = CGPoint(x: bounds.midX, y: bounds.midY)
   477→        let dx = point.x - center.x
   478→        let dy = point.y - center.y
   479→
   480→        if (dx * dx + dy * dy) > (radius * radius) {
   481→            return nil
   482→        }
   483→
   484→        return super.hitTest(point)
   485→    }
